///   3. Response.Write(data)        → return File() or Content() results
///   4. ThreadAbortException catch  → removed entirely (never thrown in .NET 8)
///   5. WebForms event handlers     → MVC action methods returning IActionResult
/// </summary>
public class ReportController : Controller
{
    // Was: btnExport_Click event handler with Response.Write + Response.End
    [HttpPost]
    public IActionResult Export()
    {
        var data = GenerateReport();

        // Return a FileContentResult — the framework handles headers and
        // flushing the response. No Response.Clear/End needed.
        return File(
            System.Text.Encoding.UTF8.GetBytes(data),
            "text/csv",
            "report.csv");
    }

